Here's how to test `DataFetcher` with proper timeout/cancellation handling in MSTest 3.x+:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange — handler that delays forever
        var handler = new FakeHandler(neverCompletes: true);
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler — no mocking library needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly bool _neverCompletes;

        public FakeHandler(string content = "", HttpStatusCode statusCode = HttpStatusCode.OK,
            bool neverCompletes = false)
        {
            _content = content;
            _statusCode = statusCode;
            _neverCompletes = neverCompletes;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_neverCompletes)
            {
                await Task.Delay(Timeout.Infinite, cancellationToken);
            }

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `[Timeout(5000)]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time expires, preventing hung tests |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type (not `[ExpectedException]`) |
| `FakeHandler` with pre-cancelled `CancellationTokenSource` | Tests that your code properly propagates cancellation |
| `sealed` test class + constructor-injected `TestContext` | Modern MSTest 3.x conventions |

The critical detail: **always pass `TestContext.CancellationToken`** to async calls in tests with `[Timeout]`. Without it, the timeout attribute has no way to interrupt the async operation, and your test can hang indefinitely.
